package com.vycepay.admin.api.v1;
import java.util.*; import com.vycepay.admin.api.v1.dto.AdminRequests.CallbackRetryRequest; import com.vycepay.admin.application.service.*; import com.vycepay.common.api.*; import jakarta.servlet.http.HttpServletRequest; import jakarta.validation.Valid; import org.springframework.http.ResponseEntity; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*;
/** Choice Bank callback monitoring APIs with audited retry. */
@RestController @RequestMapping("/api/admin/v1/callbacks") @PreAuthorize("hasAuthority('PERM_callback:view')")
public class CallbackController{private final AdminReadService r; private final AdminMutationService m; private final RateLimitService rateLimitService; public CallbackController(AdminReadService r,AdminMutationService m,RateLimitService rateLimitService){this.r=r;this.m=m;this.rateLimitService=rateLimitService;} @GetMapping public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> list(@RequestParam(required=false)Integer page,@RequestParam(required=false)Integer size,@RequestParam(required=false)String notificationType,@RequestParam(required=false)Boolean processed,@RequestParam(required=false)String fromDate,@RequestParam(required=false)String toDate){return ResponseEntity.ok(ApiSuccessResponses.ok("CALLBACKS_OK","Callbacks",r.callbacks(page,size,notificationType,processed,fromDate,toDate)));} @GetMapping("/{id}") public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> detail(@PathVariable Long id){return ResponseEntity.ok(ApiSuccessResponses.ok("CALLBACK_OK","Callback",r.callbackDetail(id)));} @PostMapping("/{id}/retry") @PreAuthorize("hasAuthority('PERM_callback:retry')") public ResponseEntity<ApiSuccessResponse<Void>> retry(@PathVariable Long id,@Valid @RequestBody CallbackRetryRequest body,HttpServletRequest req){rateLimitService.check("mutation",req);m.retryCallback(id,body,req);return ResponseEntity.ok(ApiSuccessResponses.ok("CALLBACK_RETRY_QUEUED","Callback retry queued"));}}
